from cryptography.fernet import Fernet
import base64
import os

def generate_key():
    return Fernet.generate_key()

def encrypt_credit_card(card_number, key):
    f = Fernet(key)
    encrypted_card = f.encrypt(card_number.encode())
    return encrypted_card.decode()

def decrypt_credit_card(encrypted_card, key):
    f = Fernet(key)
    decrypted_card = f.decrypt(encrypted_card.encode())
    return decrypted_card.decode()

